/// {@category Data}
library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/data/models/ai_coach/ai_coach_report.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_domain.dart';
import 'package:baseball_detector_flutter/data/models/enums/role_level.dart';
import 'package:baseball_detector_flutter/data/models/player.dart';
import 'package:baseball_detector_flutter/data/models/resource.dart';
import 'package:baseball_detector_flutter/data/models/user_info.dart';

part 'session.freezed.dart';
part 'session.g.dart';

@freezed
abstract class Session with _$Session {
  const Session._();

  @JsonSerializable(
      explicitToJson: true, fieldRename: Constants.modelFieldRename)
  const factory Session({
    @Default(null) String? id,
    @Default(null) String? userId,
    @Default(null) String? playerId,
    @Default(null) String? location,
    @Default(null) String? note,
    @Default(null) DateTime? createdAt, // assumes UTC
    @Default(null) DateTime? updatedAt, // assumes UTC
    @Default(null) bool? deleteFlag,
    @Default(null) String? teamId,
    @Default(null) String? title,
    @Default(null) Player? player,
    @Default(null) List<ResourceData>? resources,
    @Deprecated(
        'Use aiCoachReportId instead. This field will be removed when API migration is complete.')
    @JsonKey(
      fromJson: _aiCoachReportFromJson,
      toJson: _aiCoachReportToJson,
    )
    @Default(null)
    AICoachReport? aiCoachReport,
    @Default(null) String? aiCoachReportId,
  }) = _Session;

  factory Session.fromJson(Map<String, dynamic> json) =>
      _$SessionFromJson(json);

  bool isEditableByUser(
    String? currentUserId,
    UserAccessibleContents? accessibleContents,
  ) {
    // same condition as isVideoUploadableByUser
    return isVideoUploadableByUser(currentUserId, accessibleContents);
  }

  bool isVideoUploadableByUser(
    String? currentUserId,
    UserAccessibleContents? accessibleContents,
  ) {
    if (currentUserId == null || accessibleContents == null) return false;

    if (teamId == null) {
      return false;
    }
    if (accessibleContents.hasPrivilegesFor(
        teamId!, RoleDomain.basic, RoleLevel.write, true)) {
      return true;
    }
    if (userId == currentUserId &&
        accessibleContents.hasPrivilegesFor(
            teamId!, RoleDomain.basic, RoleLevel.write, false)) {
      return true;
    }
    return false;
  }
}

AICoachReport? _aiCoachReportFromJson(Map<String, dynamic>? json) {
  if (json == null || json.isEmpty) {
    return null;
  }
  return AICoachReport.fromJson(json);
}

Map<String, dynamic>? _aiCoachReportToJson(AICoachReport? report) {
  if (report == null) {
    return null;
  }
  return aiCoachReportToJson(report);
}

