import 'package:baseball_detector_flutter/data/models/ball.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/components/all_balls_container.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/hitting_scatter_chart.dart';
import 'package:baseball_detector_flutter/views/pages/home/sessions/session_details/components/pitching_scatter_chart.dart';

class SessionScatterChart extends HookConsumerWidget {
  final String teamId;
  final String sessionId;

  const SessionScatterChart({
    super.key,
    required this.teamId,
    required this.sessionId,
  });

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    return AllBallsContainer(
        teamId: teamId,
        sessionId: sessionId,
        builder: ({
          required List<Ball> hittingBalls,
          required List<Ball> pitchingBalls,
        }) {
          return SingleChildScrollView(
            child: Column(
              children: [
                // Pitching scatter chart - only show if has data
                if (pitchingBalls.isNotEmpty)
                  PitchingScatterChart(balls: pitchingBalls),
                if (pitchingBalls.isNotEmpty && hittingBalls.isNotEmpty)
                  const SizedBox(height: 24),
                // Hitting scatter chart - only show if has data
                if (hittingBalls.isNotEmpty)
                  HittingScatterChart(balls: hittingBalls),
              ],
            ),
          );
        });
  }
}

