class PitchingStats {
  // Holds average statistics for a group of balls (pitches)
  final double avgVelocity; // Average initial velocity
  final double avgVBreak; // Average vertical break
  final double avgHBreak; // Average horizontal break

  PitchingStats({
    required this.avgVelocity,
    required this.avgVBreak,
    required this.avgHBreak,
  });
}

/// A widget that displays a scatter chart of pitch break data and a summary table by pitch type.
class PitchingScatterChart extends HookConsumerWidget {
  final List<Ball> balls; // List of pitch data to visualize

  const PitchingScatterChart({
    super.key,
    required this.balls,
  });

  /// Normalize pitchType: treat null and pitchType.pitchType == 'none' as the same group (null)
  PitchType? _normalizePitchType(PitchType? pitchType) {
    if (pitchType == null || pitchType.pitchType == 'none') {
      return null;
    }
    return pitchType;
  }

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    // Get unit type and axis settings
    final unitType = ref.watch(appUnitProvider);
    final breakUnit = UnitConverter.formatBreak(0, unitType).unit;
