                Text(
                  formatNum(
                      UnitConverter.convertBreak(stats.avgVBreak, unitType)),
                  style: const TextStyle(
                      fontSize: 14, fontWeight: FontWeight.bold),
                  overflow: TextOverflow.ellipsis,
                  maxLines: 1,
                ),
              ],
            )),
            DataCell(Row(
              mainAxisAlignment: MainAxisAlignment.end,
              children: [
                Text(
                  formatNum(
                      UnitConverter.convertBreak(stats.avgHBreak, unitType)),
                  style: const TextStyle(
